// frontend/src/components/Chatbot.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";

/**
 * Weather App Chatbot
 * - Clean, colorful‑minimal UI with purple accent
 * - Mobile friendly (sticky input, safe from keyboard overlap)
 * - Message list with auto‑scroll to bottom
 * - Quick prompt chips
 * - Optional suggestions from caller via props
 * - Emits onSend(message) so the parent can call your backend /api/chat
 * - Displays isTyping spinner while awaiting response
 */

export default function Chatbot({
  className = "",
  accent = "#7C3AED", // Tailwind purple-600
  initialMessages = [
    { role: "assistant", content: "Hey! Ask me anything about the weather — forecasts, radar, or outfit ideas." },
  ],
  suggestions = [
    "Will it rain after 5 PM?",
    "How windy will it be tomorrow?",
    "Compare ECMWF vs GFS for Atlanta",
    "What should I wear tonight?",
  ],
  onSend = async (message) => {
    // Default demo echo; replace by passing a real onSend from parent
    await new Promise((r) => setTimeout(r, 500));
    return { role: "assistant", content: `You said: ${message}` };
  },
}) {
  const [messages, setMessages] = useState(initialMessages);
  const [input, setInput] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const listRef = useRef(null);

  // Auto‑scroll to bottom when messages change
  useEffect(() => {
    const el = listRef.current;
    if (!el) return;
    el.scrollTo({ top: el.scrollHeight, behavior: "smooth" });
  }, [messages, isTyping]);

  const canSend = input.trim().length > 0 && !isTyping;

  const sendMessage = async (text) => {
    const content = text.trim();
    if (!content) return;

    const next = [...messages, { role: "user", content }];
    setMessages(next);
    setInput("");
    setIsTyping(true);

    try {
      const reply = await onSend(content);
      if (reply && reply.content) {
        setMessages((prev) => [...prev, reply]);
      } else {
        setMessages((prev) => [
          ...prev,
          { role: "assistant", content: "(No response received)" },
        ]);
      }
    } catch (err) {
      console.error(err);
      setMessages((prev) => [
        ...prev,
        { role: "assistant", content: "Sorry, I ran into an error. Try again." },
      ]);
    } finally {
      setIsTyping(false);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (canSend) sendMessage(input);
  };

  const bubble = (m, i) => {
    const isUser = m.role === "user";
    return (
      <div key={i} className={`flex ${isUser ? "justify-end" : "justify-start"}`}>
        <div
          className={`max-w-[85%] md:max-w-[70%] rounded-2xl px-4 py-3 shadow-sm border text-sm md:text-[15px] leading-relaxed whitespace-pre-wrap`} 
          style={{
            background: isUser ? accent : "rgba(255,255,255,0.7)",
            color: isUser ? "white" : "#111827",
            borderColor: isUser ? "transparent" : "rgba(255,255,255,0.6)",
            backdropFilter: isUser ? undefined : "saturate(130%) blur(6px)",
          }}
        >
          {m.content}
        </div>
      </div>
    );
  };

  return (
    <div className={`relative w-full h-full flex flex-col bg-transparent ${className}`}>
      {/* Header */}
      <div className="sticky top-0 z-20 px-4 py-3 flex items-center gap-2">
        <div className="h-3 w-3 rounded-full" style={{ background: accent }}></div>
        <h3 className="text-base md:text-lg font-semibold">Weather Chat</h3>
        <div className="ml-auto text-xs opacity-60">ECMWF‑aware</div>
      </div>

      {/* Message list */}
      <div ref={listRef} className="flex-1 overflow-y-auto px-4 pb-28 md:pb-4 space-y-3">
        {messages.map(bubble)}
        {isTyping && (
          <div className="flex items-center gap-2 text-sm opacity-80">
            <div className="h-2 w-2 rounded-full animate-bounce" style={{ background: accent }} />
            <div className="h-2 w-2 rounded-full animate-bounce [animation-delay:120ms]" style={{ background: accent }} />
            <div className="h-2 w-2 rounded-full animate-bounce [animation-delay:240ms]" style={{ background: accent }} />
            <span className="ml-2">Thinking…</span>
          </div>
        )}
      </div>

      {/* Quick prompts (mobile friendly, horizontal scroll) */}
      {suggestions?.length > 0 && (
        <div className="px-4 pb-2 md:pb-0">
          <div className="flex gap-2 overflow-x-auto no-scrollbar">
            {suggestions.map((s, i) => (
              <button
                key={i}
                onClick={() => sendMessage(s)}
                className="shrink-0 rounded-full px-3 py-2 text-xs border bg-white/70 hover:bg-white transition"
                style={{ borderColor: "rgba(0,0,0,0.05)" }}
              >
                {s}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Input dock */}
      <form
        onSubmit={handleSubmit}
        className="fixed bottom-0 left-0 right-0 z-30 px-4 pb-[env(safe-area-inset-bottom)] pt-2"
      >
        <div
          className="max-w-3xl mx-auto flex items-center gap-2 rounded-2xl border bg-white/80 backdrop-blur px-3 py-2 shadow-md"
          style={{ borderColor: "rgba(0,0,0,0.06)" }}
        >
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask about the weather…"
            className="flex-1 bg-transparent outline-none text-sm md:text-base placeholder:opacity-60"
          />
          <button
            type="submit"
            disabled={!canSend}
            className="rounded-xl px-4 py-2 text-sm font-medium text-white disabled:opacity-50"
            style={{ background: accent }}
          >
            Send
          </button>
        </div>
      </form>
    </div>
  );
}

/* Optional: hide scrollbar utility (Tailwind plugin-free) */
// Add to a global CSS if you want; used above as `no-scrollbar`
// .no-scrollbar::-webkit-scrollbar { display: none; }
// .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }


